<?php
namespace App\Services\Audit;use App\Models\AuditLog;use Illuminate\Database\Eloquent\Model;use Illuminate\Support\Facades\Auth;
class AuditLogService{public function log(string $action,mixed $subject=null,array $oldValues=[],array $newValues=[],?int $workspaceId=null):void{$user=Auth::user();$request=request();AuditLog::create(['workspace_id'=>$workspaceId ?? ($subject instanceof Model ? ($subject->workspace_id ?? null) : null),'user_id'=>$user?->id,'actor_type'=>$user?->isPlatformUser()?'platform':($user?'tenant':'system'),'action'=>$action,'subject_type'=>$subject instanceof Model?$subject::class:null,'subject_id'=>$subject instanceof Model?$subject->getKey():null,'old_values'=>$oldValues ?: null,'new_values'=>$newValues ?: null,'ip_address'=>$request?->ip(),'user_agent'=>$request?->userAgent()]);}}
